var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"교수님. 환자가 심정지 상태입니다.","JPN":"教授、患者が心肺停止状態です。","ENG":"The patient is going through cardiac arrest, Professor.","TWN":"教授，患者的心臟停止挑動了。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP5"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"바로 제세동 실시해야죠. 100줄 충전하세요.","JPN":"ただちに除細動を実施します。100ジュールチャージ。","ENG":"Charge the defibrillator. 100 Joules.","TWN":"馬上開始電擊，100焦耳。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"흐음...... 목격자까지 모두 확실하게 처리했구나.","JPN":"ふーん……目撃者まで全員もれなく処理したみたいね。","ENG":"Hmm... So you've taken care of all the witnesses, too.","TWN":"嗯……不錯，連目擊者都處理乾淨了。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"의뢰인이 무척 기뻐하겠어. 그렇지 않니, 베로니카?","JPN":"依頼人も大喜びするでしょうね。そうでしょう、ベロニカ？","ENG":"Our client will be most satisfied. Don't you think so, Veronica?","TWN":"委託人應該會很滿意，是吧，貝洛妮卡？"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇습니다, 주인님.","JPN":"おっしゃるとおりです、ご主人様。","ENG":"Yes, Master.","TWN":"是的，主人。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"새로 기르는 꽃도 솜씨가 꽤 나아졌던걸.","JPN":"新しく育てている花もずいぶん腕があがってきたじゃない。","ENG":"And the new flower has improved substantially.","TWN":"新養的花長得不錯，手藝有長進。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"백합치고는 너무 새카매서 뽑아 버리려고 했는데.","JPN":"百合というにはあまりにも真っ黒だったから、引き抜いてやろうと思ったんだけどね。","ENG":"I was thinking of plucking her since she's far too dark to be a pretty lily.","TWN":"這個百合太黑了，本想拔掉的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......감사합니다. 장차 주인님을 보필할 수 있게 공들여 기르고 있습니다.","JPN":"……ありがとうございます。将来はご主人様にしっかり奉仕できるよう、丹念に育てております。","ENG":"Thank you. I've been tending to her with extra care to serve you well in the future.","TWN":"……謝謝您的誇讚。我會好好養護的，希望以後能幫到主人。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"무슨 일이니? 오늘따라 표정이 어둡네?","JPN":"あら、どうしたの？　今日はなんだか浮かない顔してるじゃない。","ENG":"What's wrong? You seem particularly unwell today.","TWN":"有什麼事嗎？今天你的臉色不太好啊。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"혹시 현장에 탄피라도 떨어뜨리고 왔니? 아니면 사고사로 위장한 게 탄로날까 봐?","JPN":"現場に薬莢でも落としてきたのかしら？　それとも事故死に偽装したのがバレるのが心配なの？","ENG":"Did you happen to leave any shell casings back at the scene? Or are you worried that they'll find out the death wasn't an accident?","TWN":"在現場留下彈殼了？還是怕偽裝成意外事故事情會暴露？"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"후훗. 나도 참 실없는 소리를. 네가 그런 초보적인 실수를 저지를 리 없지.","JPN":"フフッ。あり得ないわね。あなたがそんな初歩的なミスを犯すはずないわ。","ENG":"Hah hah, what am I saying. Of course you wouldn't make such an amateur mistake.","TWN":"哈哈，我亂說的，你是不會犯這種低級錯誤的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"한 가지 드릴 말씀이 있습니다.","JPN":"一つお聞きしたいことがあります。","ENG":"There's something I must tell you.","TWN":"我想問您一件事。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"나의 사랑하는 메이드장이 무슨 이야기를 할지 궁금한걸. 말해 보렴.","JPN":"我が愛おしいメイド長から何のお話かしら。言ってごらんなさい。","ENG":"I'm eager to hear what my dear Chief Maid has to say. Speak.","TWN":"我親愛的女僕長，說說你的疑問。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이번 잡초를...... 어째서 솎아내기로 하셨는지 궁금합니다.","JPN":"今回の雑草を……どのような理由で刈ることにしたのか気になります。","ENG":"I'm curious... why you decided to pluck out this weed.","TWN":"為什麼您……決定除去這次的雜草。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"지금 내 명령에 의문을 표하는 거니?","JPN":"私の命令に疑問があるってことかしら？","ENG":"Are you questioning my orders?","TWN":"你是在對我的命令有所懷疑？"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇지 않습니다. 다만......","JPN":"いいえ、ただ……","ENG":"No. It's just that...","TWN":"沒有，只不過……"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"다만?","JPN":"ただ？","ENG":"Just what?","TWN":"只不過？"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이번 잡초는 이력상 아무런 하자도 없었습니다.","JPN":"今回の雑草は履歴上、何の問題もありませんでした。","ENG":"The weed had no history of any defects.","TWN":"這次的雜草從未出現過任何的問題。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"범죄를 저지른 것도, 음모를 꾸민 것도 아니었습니다.","JPN":"犯罪を犯したわけでも、陰謀を企んだわけでもありませんでした。","ENG":"He never committed any crimes, or plotted any conspiracies.","TWN":"沒有犯罪，也沒計畫過什麼陰謀。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"더구나 그 남자에게는...... 아직 어린 딸아이들도 있더군요.","JPN":"それにあの男には……まだ幼い子どもたちもいました。","ENG":"And furthermore, he had... very young daughters.","TWN":"而且那個男人……還有年幼的女兒們。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"굳이 솎아낼 필요까지는 없었던 것 아닌가 하여......","JPN":"わざわざ刈る必要があったのかが……","ENG":"Perhaps there was no reason to go so far as to pluck him…","TWN":"為什麼一定要除掉他呢……"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"후훗. 그동안 잡초를 너무 많이 솎아냈나 보구나.","JPN":"あらあら。草むしりの仕事が長すぎたのかしら。","ENG":"Hah hah. It seems you've been plucking out too many weeds.","TWN":"呼呼，看來你是除雜草除得多了。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"풀잎이 바스락거리는 소리 따위에 귀를 기울이다니.","JPN":"たかが草ごときが発する音なんかに耳を傾けるなんて。","ENG":"There is no need to pay attention to the rustling of the leaves.","TWN":"居然會對那種微不足道的雜草動惻隱之心。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만, 마스터......","JPN":"しかし、マスター……","ENG":"But Master...","TWN":"但是，主人……"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"우리 맨션은 오랫동안 정원을 손질해 왔어. 모두 이 세상을 아름답게 가꾸기 위해서였지.","JPN":"我がマンションは長年にわたり庭園の手入れをしてきたの。すべて、この世を美しくするために。","ENG":"The Mansion has been tending to the garden for a very long time, all to shape this world beautifully.","TWN":"我們曼森很久以來一直做修理庭院的工作，就是為了讓這個世界變得更美好。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"그러니 그들이 뭐라고 떠들든 우리가 신경 쓸 일은 아냐.","JPN":"だから刈られる運命の雑草が何を言おうが、私たちが気にすることないわよ。","ENG":"So no matter what they might say, that's none of our concern.","TWN":"不管他們說什麼，也不是我們該管的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"정원사가 정원에 잡초가 무성하게 내버려 둘 수는 없잖니.","JPN":"庭師が庭に雑草を生い茂らせておくわけにはいかないじゃない。","ENG":"The gardener simply cannot allow weeds to overrun the garden.","TWN":"作為園藝師總不能放任雜草茂盛。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"마음이 흔들리는 건 꽃이 시들어간다는 징조야, 베로니카.","JPN":"心が揺れるということは、花が萎れていく兆しよ、ベロニカ。","ENG":"A faltering mind is a sign that the flower is wilting, Veronica.","TWN":"心有所動搖，說明花開始謝了，貝洛妮卡。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"내가 기른 꽃들 중에 가장 걸작인 네가 그래서는 안 되지.","JPN":"私が育てた花の中で最も傑作であるあなたが、そうなってはいけないでしょう。","ENG":"You're the greatest masterpiece of all the flowers I've raised. You mustn't go down that path.","TWN":"我養的所有花中，你是最佳的傑作，是最不該有這種心思的。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"아무래도 잠시 쉬는 편이 좋겠구나.","JPN":"どうやら少し休んだほうがよさそうね。","ENG":"I suppose you should take a short break.","TWN":"看來你需要休息一陣子了。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"면목 없습니다. 마스터.","JPN":"面目ございません、マスター。","ENG":"Forgive me, Master.","TWN":"對不起，主人。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"하지만 쉬기 전에, 한 가지 해 줘야 할 일이 있단다.","JPN":"でも休む前に、一つやってほしい仕事があるわ。","ENG":"But before you take that break, there's one more thing I need you to do for me.","TWN":"不過這之前，你需要為我辦一件事。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASTER_NPC_MANSION_SILHOUETTE2","text":{"KOREA":"그렇게 어렵진 않을 거야.","JPN":"あまり難しくない仕事だから安心して。","ENG":"It shouldn't be that hard.","TWN":"事情並不難。"},"stage":{"bg":"CRUISE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_SILHOUETTE2","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"심전도 그래프에 반응 없습니다.","JPN":"心電図グラフに反応ありません。","ENG":"The ECG shows no response.","TWN":"心電圖上沒有反應。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP5"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"한 번 더 갑니다. 150줄 충전하세요.","JPN":"もう一度行きます。150ジュールチャージ。","ENG":"Let's go one more time. 150 Joules, stat.","TWN":"再來一次，150焦耳。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"여기는 정찰대. 항만에서 타깃을 발견했다.","JPN":"こちらは偵察隊。ターゲットを発見した。","ENG":"Scout team here. We've identified the target at the harbor.","TWN":"這裡是偵察隊，在港灣發現了目標。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>스푼 하나로 두 명을 중태에 빠뜨린 여자다. 절대 가까이 접근하지 말고 퇴로만 막도록.</color>","JPN":"<color=#ffd34c>スプーン一本で二人に重症を負わせた女だ。くれぐれも接近せずに退路だけ防ぐように。</color>","ENG":"<color=#ffd34c>She put two men in the ICU with just a spoon. Whatever you do, do not engage. Just cut off her escape route.</color>","TWN":"<color=#ffd34c>那個女人僅用一個勺子就將兩個人打成重傷。去守住她的退路，但不要靠近她。</color>"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L10_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"스푼? 그게 무슨 헛소리야?","JPN":"スプーン？　冗談か？","ENG":"A spoon? Are you kidding me?","TWN":"勺子？什麼亂七八糟的？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"뭐야, 저 여자. 고작 권총으로 이 먼 거리를 겨냥해서 어떻게 하겠다고......","JPN":"なんだ、あの女。あんな拳銃でこの距離を狙ってどうするつも……","ENG":"Is she aiming at us with a pistol? There's no way she could hit us from that distance—","TWN":"什麼啊，那個女的就憑一把手槍，怎麼瞄準這麼遠的距離……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_B","text":{"KOREA":"크헉!?","JPN":"ぐはっ……！","ENG":"Hngh!?","TWN":"額！？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_GUN_FIRE_BIG"},{"id":"L14_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"이런 미친......!","JPN":"そんなバカな……！","ENG":"Holy smoke!","TWN":"這瘋子……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_A","text":{"KOREA":"쏴 버려! 어서 고개 못 들게 쏴 버리라고!","JPN":"撃っちまえ！　視野を確保する前にはやく撃て！","ENG":"Shoot her! Don't let her raise her head!","TWN":"開槍！快開槍，打死她！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"큭......!","JPN":"クッ……！","ENG":"Ugh!","TWN":"唔……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기는 숙면 담당. 배신자와 접촉했습니다.","JPN":"こちら睡眠担当。裏切り者と接触しました。","ENG":"This is the Bed Maid. I've made contact with the traitor.","TWN":"這裡是睡眠擔當，已和叛徒碰頭。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L24_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"전 인원 경계 태세로. 정원 손질이 끝나기 전까지 접근하는 자들은 모두 배제하세요.","JPN":"全員警戒態勢を。庭園の手入れが終わるまで、近付く者はすべて排除してください。","ENG":"All personnel are to enter the alert posture. Deny access to everyone until the garden has been tended to.","TWN":"全員警戒。庭院修理結束之前，不准任何人靠近。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......릴리.","JPN":"……リリー。","ENG":"Lily.","TWN":"……莉莉。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"혼신을 다해 주인을 모시는 것이 메이드가 할 일이라고 가르쳐 준 건 당신 아니었나요?","JPN":"身を尽くしてご主人様に仕えるのがメイドの仕事だと教えてくれたのはあなたでした。","ENG":"You were the one who taught me that a maid should serve her master with all her heart.","TWN":"是你告訴我，女僕應該竭盡全力侍奉主人吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"어째서 지시를 거스른 걸로도 모자라, 주인님께 반역을 저지르려 했죠?","JPN":"どうして指示に逆らう上に、ご主人様に反逆を起こそうとしたのですか？","ENG":"Yet you not only disobeyed our Master, but conspired to commit treason!","TWN":"為什麼你卻要反抗主人的命令，還要背叛主人？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"변명할 말이 있다면 어디 해 보세요, 메이드장님.","JPN":"言い訳があるなら言ってみてください、メイド長。","ENG":"What do you have to say for yourself, Chief Maid?","TWN":"女僕長，你有什麼話可說？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마스터가 여기로 보내던가요? 저를 솎아내라고 하면서?","JPN":"マスターの指示で来たのですか？　私を間引くために？","ENG":"Did the Master send you here? To pluck me out?","TWN":"是主人讓你來的？讓你殺我？"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네. 저는 언행이 일치하지 않는 당신과 다르니까요.","JPN":"はい。私は言行が一致しないあなたとは違いますから。","ENG":"Yes. Unlike you, I act on my words.","TWN":"是，因為我和言行不一的你不一樣。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"주인의 지시 없이 뛰쳐나올 만큼 불손한 짓은 저지르지 않습니다.","JPN":"ご主人様の指示なしで動くような不遜なことはしません。","ENG":"I would never be so treacherous as to run off without the Master's express instructions.","TWN":"你沒有主人的命令擅自出逃，我可不會做這麼不恭敬的事情。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이것도 다 당신이 메이드의 자세라고 가르쳐 준 거지만요.","JPN":"これもすべて、メイドの心構えとあなたに教えてもらったことです。","ENG":"Of course, I learned all about this from you. This is how a maid is supposed to behave.","TWN":"當然，這也是你教我的，所謂女僕的姿態。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래요. 그렇다면 지금은 당신의 질문에 대답해 드릴 수 없겠군요.","JPN":"そうだったのですね。ならば今あなたの質問にお答えすることはできません。","ENG":"I see. In that case, I won't be able to answer your question at the moment.","TWN":"好吧， 既已如此，我也不能回答你的問題了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"막다른 곳에 몰려 놓고도 그런 쓸데없는 고집이나 부리다니......","JPN":"土壇場に追い詰められても、そんな無駄な意地を張るなんて……","ENG":"You still choose to be so stubborn even when you've been cornered?","TWN":"死到臨頭了還這麼嘴硬……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"반항은 포기하고 얌전히 붙잡히는 편이 나을 겁니다.","JPN":"抵抗はやめて大人しく投降してください。それが身のためでしょう。","ENG":"Resistance is futile. I advise you surrender quietly instead.","TWN":"放棄抵抗，乖乖束手就擒吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그리고 가서 마스터께 용서를 구하세요.","JPN":"そしてマスターのもとへ戻り、許しを求めてください。","ENG":"And go beg the Master for forgiveness.","TWN":"然後去跟主人求饒。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"걱정해 주는 마음은 이해하지만, 제안을 받아들일 수는 없겠군요.","JPN":"心配してくださる気持ちは理解しますが、提案を受けることはできません。","ENG":"I appreciate your concerns, but I'm afraid I can't accept your offer.","TWN":"謝謝你的好意，不過我無法接受你的提議。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"돌아가서 마스터에게 전하세요. 전 더 이상 당신의 꽃이 아니라고.","JPN":"お戻りになって、マスターにお伝えください。私はもうあなた様の花ではないと。","ENG":"Please go tell the Master that I am no longer her flower.","TWN":"回去後告訴主人，我已不是主人養的一朵花了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"누구 마음대로 그런 무례한 소리를!","JPN":"無礼なことを！","ENG":"How dare you!","TWN":"你膽敢說出這麼無禮的話！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이유는 이제 궁금하지도 않아요. 완전히 못쓸 정도로 망가져 버렸군요.","JPN":"もう理由はどうでもいいです。手の施しようがないくらい、壊れてしまったようですね。","ENG":"I'm no longer even curious about why you'd do this. You've been ruined so completely that you're useless.","TWN":"我現在也不想知道了，你已經變得無可救藥了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"맨션에서 마스터의 명령은 절대적입니다.","JPN":"マンションにおいてマスターの命令は絶対です。","ENG":"The Master's commands are absolute in the Mansion.","TWN":"在曼森，主人的命令就是絕對不可違逆的。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런데 역대 최고의 메이드장이라 불리던 당신이 그런 만행을 저지르다니......","JPN":"それなのに歴代最高のメイド長と呼ばれていたあなたが、そんな愚行を犯すなんて……","ENG":"And yet, the greatest Chief Maid in history committed such treason...","TWN":"沒想到你這個歷代最優秀的女僕長，居然會做出這樣的事……"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"용서할 수 없어요.","JPN":"認められません。","ENG":"You must pay for this.","TWN":"我無法饒恕你。"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기서 반드시, 당신을 벌하겠습니다!","JPN":"あなたにはこの場で、必ず裁きを受けていただきます。","ENG":"I will punish you accordingly, here and now!","TWN":"我今天必須懲罰你！"},"stage":{"bg":"DOCK_NIGHT","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};